+    );
+    assert!(
+        !stdout.contains("[FAIL] stress/"),
+        "Should not run stress scenarios when filtered to smoke"
+    );
+    assert!(
+        !stdout.contains("[FAIL] fault/"),
+        "Should not run fault scenarios when filtered to smoke"
+    );
+}

