+#[test]
+fn interpose_allowlist_covers_all_call_through_modules() {
+    let profile = load_profile();
+    let abi_src = workspace_root().join("crates/glibc-rs-abi/src");
+
+    let allowlist: HashSet<String> = profile["interpose_allowlist"]["modules"]
+        .as_array()
