+        let actual = *module_counts
+            .get(&("GlibcCallThrough".to_string(), module.clone()))
+            .unwrap_or(&0);
+        assert_eq!(
+            claimed, actual,
+            "callthrough_breakdown.{module}: claimed={claimed} matrix={actual}"
