+#[test]
+fn status_progression_consistent() {
+    let lvl = load_levels();
+    let levels = lvl["levels"].as_array().unwrap();
+
+    let status_order: HashMap<&str, usize> = [
+        ("achieved", 0),
+        ("in_progress", 1),
+        ("planned", 2),
+        ("roadmap", 3),
+    ]
+    .into_iter()
+    .collect();
+
+    let valid_statuses: HashSet<&str> = ["achieved", "in_progress", "planned", "roadmap"]
+        .into_iter()
+        .collect();
