+#[test]
+fn no_panics_or_todo() {
+    let contracts = load_contracts();
+    let entries = contracts["contracts"].as_array().unwrap();
+
+    for entry in entries {
+        let sym = entry["symbol"].as_str().unwrap_or("<unknown>");
+        let behavior = &entry["behavior"];
+
+        assert_eq!(
